diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..d221b1a71486 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -662,6 +662,50 @@ static Value *foldLogOpOfMaskedICmps(Value *LHS, Value *RHS, bool IsAnd,
       if (!match(C, m_APInt(OldConstC)) || !match(E, m_APInt(OldConstE)))
         return nullptr;

+      // Special case: (icmp eq X, C) | (icmp eq (X & Mask), C+1)
+      // where Mask = ~((1<<K)-1) and (C+1) & ~Mask == 0.
+      // Equivalent to: (X - C) < (2^K + 1)
+      if (!IsAnd && PredL == ICmpInst::ICMP_EQ && PredR == ICmpInst::ICMP_EQ) {
+        const APInt *ExactC = nullptr, *TheMask = nullptr;
+        const APInt *MaskVal = nullptr;
+        ICmpInst *MaskedICmp = nullptr;
+        if (ConstB->isAllOnes() && !ConstD->isAllOnes()) {
+          ExactC = OldConstC;
+          MaskVal = OldConstE;
+          TheMask = ConstD;
+          MaskedICmp = cast<ICmpInst>(RHS);
+        } else if (ConstD->isAllOnes() && !ConstB->isAllOnes()) {
+          ExactC = OldConstE;
+          MaskVal = OldConstC;
+          TheMask = ConstB;
+          MaskedICmp = cast<ICmpInst>(LHS);
+        }
+        if (ExactC && *ExactC + 1 == *MaskVal) {
+          APInt NotMask = ~(*TheMask);
+          APInt RangeSize = NotMask + 1; // 2^K
+          if (RangeSize.isPowerOf2() && RangeSize.ugt(1) &&
+              (*MaskVal & NotMask) == 0) {
+            // If the masked icmp's operand is an 'and' with more than one
+            // use, we can't replace it without keeping the 'and' instruction.
+            bool HasMultiUseAnd = false;
+            for (Value *Op : {MaskedICmp->getOperand(0),
+                              MaskedICmp->getOperand(1)}) {
+              if (auto *I = dyn_cast<BinaryOperator>(Op))
+                if (I->getOpcode() == Instruction::And &&
+                    I->getNumUses() > 1)
+                  HasMultiUseAnd = true;
+            }
+            if (!HasMultiUseAnd) {
+              APInt RangeLimit = RangeSize + 1; // 2^K + 1
+              Value *Sub = Builder.CreateAdd(
+                  A, ConstantInt::get(A->getType(), -(*ExactC)));
+              return Builder.CreateICmp(ICmpInst::ICMP_ULT, Sub,
+                  ConstantInt::get(A->getType(), RangeLimit));
+            }
+          }
+        }
+      }
+
       auto FoldBMixed = [&](ICmpInst::Predicate CC, bool IsNot) -> Value * {
         CC = IsNot ? CmpInst::getInversePredicate(CC) : CC;
         const APInt ConstC = PredL != CC ? *ConstB ^ *OldConstC : *OldConstC;
@@ -3539,6 +3583,37 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);

+  // Transform (X == C1) | ((X & M) == C2) -> (X - C1) < ~M + 2
+  // when C1 = C2 - 1 and C2 is aligned to M (i.e., C2 has no bits in the
+  // lower bits cleared by M). For 'and' with inverse predicates, use uge.
+  if (PredL == PredR &&
+      PredL == (IsAnd ? ICmpInst::ICMP_NE : ICmpInst::ICMP_EQ)) {
+    Value *A;
+    const APInt *C1, *M, *C2;
+    // Pattern: (icmp Pred X, C1) op (icmp Pred (and X, M), C2)
+    if (match(RHS0, m_And(m_Value(A), m_APInt(M))) && LHS0 == A &&
+        match(LHS1, m_APInt(C1)) && match(RHS1, m_APInt(C2)) &&
+        *C1 == *C2 - 1 && (*C2 & ~(*M)).isZero() && (~(*M)).isMask()) {
+      APInt RangeSize = ~(*M) + 2;
+      Value *Sub = Builder.CreateSub(A, ConstantInt::get(A->getType(), *C1));
+      ICmpInst::Predicate NewPred =
+          IsAnd ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_ULT;
+      return Builder.CreateICmp(NewPred, Sub,
+                                ConstantInt::get(A->getType(), RangeSize));
+    }
+    // Pattern: (icmp Pred (and X, M), C2) op (icmp Pred X, C1)
+    if (match(LHS0, m_And(m_Value(A), m_APInt(M))) && RHS0 == A &&
+        match(RHS1, m_APInt(C1)) && match(LHS1, m_APInt(C2)) &&
+        *C1 == *C2 - 1 && (*C2 & ~(*M)).isZero() && (~(*M)).isMask()) {
+      APInt RangeSize = ~(*M) + 2;
+      Value *Sub = Builder.CreateSub(A, ConstantInt::get(A->getType(), *C1));
+      ICmpInst::Predicate NewPred =
+          IsAnd ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_ULT;
+      return Builder.CreateICmp(NewPred, Sub,
+                                ConstantInt::get(A->getType(), RangeSize));
+    }
+  }
+
   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }

